import{_ as a}from"./chunks/文件受限图.DsG20F9s.js";import{_ as t,o as i,c as o,a2 as l}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"Image Moderation and Access Mode","description":"","frontmatter":{},"headers":[],"relativePath":"en/Safety/image-moderation-and-access-mode.md","filePath":"en/Safety/image-moderation-and-access-mode.md","lastUpdated":1781962217000}'),n={name:"en/Safety/image-moderation-and-access-mode.md"};function r(s,e,d,c,h,m){return i(),o("div",null,[...e[0]||(e[0]=[l('<h1 id="image-moderation-and-access-mode" tabindex="-1">Image Moderation and Access Mode <a class="header-anchor" href="#image-moderation-and-access-mode" aria-label="Permalink to &quot;Image Moderation and Access Mode&quot;">​</a></h1><p>Image moderation assigns age ratings to uploaded images. Access mode controls which ratings are visible through public access.</p><p>This affects the public gallery, public file URLs, and the random image API. It does not restrict the admin panel. Administrators can still view and manage all files.</p><h2 id="where-to-configure-it" tabindex="-1">Where To Configure It <a class="header-anchor" href="#where-to-configure-it" aria-label="Permalink to &quot;Where To Configure It&quot;">​</a></h2><p>Open the admin panel, then go to:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; Upload Management -&gt; Image Moderation</span></span></code></pre></div><p>The main settings are:</p><ul><li>Access mode</li><li>Enable moderation</li><li>Moderation provider</li></ul><h2 id="what-access-mode-does" tabindex="-1">What Access Mode Does <a class="header-anchor" href="#what-access-mode-does" aria-label="Permalink to &quot;What Access Mode Does&quot;">​</a></h2><p>Access mode decides which age ratings can be shown publicly.</p><p>Current modes:</p><table tabindex="0"><thead><tr><th>Access Mode</th><th>Publicly Visible Ratings</th></tr></thead><tbody><tr><td>Adult mode</td><td>General, R12, R16, R18</td></tr><tr><td>Youth mode</td><td>General, R12, R16</td></tr><tr><td>Teen mode</td><td>General, R12</td></tr><tr><td>Child mode</td><td>General only</td></tr></tbody></table><p>The default is Adult mode.</p><p>For private sites or sites with mature content, Adult mode may be appropriate. For a more conservative public gallery, choose Youth, Teen, or Child mode.</p><h2 id="what-enabling-moderation-does" tabindex="-1">What Enabling Moderation Does <a class="header-anchor" href="#what-enabling-moderation-does" aria-label="Permalink to &quot;What Enabling Moderation Does&quot;">​</a></h2><p>When moderation is enabled, ImgBed calls the selected moderation provider during upload and saves the detected age rating.</p><p>Main ratings:</p><table tabindex="0"><thead><tr><th>Rating</th><th>Meaning</th></tr></thead><tbody><tr><td>General</td><td>Safe public content</td></tr><tr><td>R12</td><td>Mildly sensitive content</td></tr><tr><td>R16</td><td>Moderately sensitive content</td></tr><tr><td>R18</td><td>Adult content</td></tr></tbody></table><p>The moderation result is used when deciding public access.</p><p>If moderation is not enabled, or old files do not have a rating, those files are treated as unrated. Unrated files are not automatically removed from the public gallery or random image API just because no rating exists.</p><h2 id="choosing-a-moderation-provider" tabindex="-1">Choosing a Moderation Provider <a class="header-anchor" href="#choosing-a-moderation-provider" aria-label="Permalink to &quot;Choosing a Moderation Provider&quot;">​</a></h2><p>Available providers include:</p><ul><li>moderatecontent.com</li><li>nsfwjs</li><li>Sightengine</li></ul><p>Each provider has different requirements:</p><ul><li>moderatecontent.com usually requires an API Key.</li><li>nsfwjs usually requires an API endpoint URL.</li><li>Sightengine requires an API user and API secret.</li></ul><p>Choose based on your account, availability, and detection quality. As long as moderation is enabled and configured correctly, ImgBed attempts to write an image rating during upload.</p><h2 id="effect-on-the-public-gallery" tabindex="-1">Effect on the Public Gallery <a class="header-anchor" href="#effect-on-the-public-gallery" aria-label="Permalink to &quot;Effect on the Public Gallery&quot;">​</a></h2><p>The public gallery filters files according to access mode.</p><p>Examples:</p><ul><li>Adult mode: R18 images can appear.</li><li>Youth mode: R18 images are hidden.</li><li>Teen mode: R16 and R18 images are hidden.</li><li>Child mode: only General images are shown.</li></ul><p>This only affects normal public access. The admin panel still shows all files.</p><h2 id="effect-on-public-file-urls" tabindex="-1">Effect on Public File URLs <a class="header-anchor" href="#effect-on-public-file-urls" aria-label="Permalink to &quot;Effect on Public File URLs&quot;">​</a></h2><p>Public file URLs are direct image links opened by visitors.</p><p>If the file rating is allowed by the current access mode, ImgBed returns the original image.</p><p>If the rating is above the allowed level, normal public access does not return the original image. Instead, ImgBed returns the configured blocked result or placeholder image.</p><p>Example:</p><ul><li>The current mode is Child mode.</li><li>An image is rated R18.</li><li>A visitor opens the public URL directly.</li><li>ImgBed does not return the R18 original image to that visitor.</li></ul><p><img src="'+a+'" alt="Restricted file image" loading="lazy"></p><p>Administrators viewing files in the admin panel are not affected by this restriction.</p><h2 id="effect-on-the-random-image-api" tabindex="-1">Effect on the Random Image API <a class="header-anchor" href="#effect-on-the-random-image-api" aria-label="Permalink to &quot;Effect on the Random Image API&quot;">​</a></h2><p>The random image API also filters its candidate pool by access mode.</p><p>In Child mode, random images are selected only from General-rated files.</p><p>In Youth mode, random images may come from General, R12, and R16 files, but not R18 files.</p><p>This prevents the random image API from bypassing public gallery restrictions.</p><h2 id="relationship-with-list-rules" tabindex="-1">Relationship With List Rules <a class="header-anchor" href="#relationship-with-list-rules" aria-label="Permalink to &quot;Relationship With List Rules&quot;">​</a></h2><p>Access mode is not the only public access rule. It works together with allow/block list rules.</p><p>In simple terms:</p><ul><li>Allowlisted content is public first.</li><li>Blocklisted content cannot be viewed directly by regular visitors.</li><li>Content that is not on either list is then checked against access mode.</li></ul><p>If an image is restricted by both age rating and list rules, regular visitors still cannot view the original file directly.</p><h2 id="recommended-settings" tabindex="-1">Recommended Settings <a class="header-anchor" href="#recommended-settings" aria-label="Permalink to &quot;Recommended Settings&quot;">​</a></h2><p>For public sites:</p><ul><li>Enable moderation.</li><li>Choose an access mode that matches the site&#39;s audience.</li><li>Use Child mode or Teen mode for all-age visitors.</li><li>Avoid Adult mode if you do not want mature content shown publicly.</li><li>Review file ratings in the admin panel and adjust manually when needed.</li></ul><p>For private or personal sites:</p><ul><li>Adult mode is usually fine.</li><li>Enable moderation if useful.</li><li>Review and adjust ratings in the admin panel as needed.</li></ul><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="will-files-disappear-from-the-admin-panel-after-i-change-access-mode" tabindex="-1">Will Files Disappear From the Admin Panel After I Change Access Mode? <a class="header-anchor" href="#will-files-disappear-from-the-admin-panel-after-i-change-access-mode" aria-label="Permalink to &quot;Will Files Disappear From the Admin Panel After I Change Access Mode?&quot;">​</a></h3><p>No.</p><p>Access mode only affects normal public access. It does not affect the admin panel.</p><h3 id="why-did-the-public-gallery-show-fewer-images-after-switching-to-child-mode" tabindex="-1">Why Did the Public Gallery Show Fewer Images After Switching to Child Mode? <a class="header-anchor" href="#why-did-the-public-gallery-show-fewer-images-after-switching-to-child-mode" aria-label="Permalink to &quot;Why Did the Public Gallery Show Fewer Images After Switching to Child Mode?&quot;">​</a></h3><p>Child mode only allows General-rated files to be shown publicly. R12, R16, and R18 files are filtered out.</p><h3 id="can-public-urls-still-open-adult-images" tabindex="-1">Can Public URLs Still Open Adult Images? <a class="header-anchor" href="#can-public-urls-still-open-adult-images" aria-label="Permalink to &quot;Can Public URLs Still Open Adult Images?&quot;">​</a></h3><p>If the current access mode does not allow that rating, normal public URLs do not return the original image.</p><h3 id="can-the-random-image-api-return-restricted-images" tabindex="-1">Can the Random Image API Return Restricted Images? <a class="header-anchor" href="#can-the-random-image-api-return-restricted-images" aria-label="Permalink to &quot;Can the Random Image API Return Restricted Images?&quot;">​</a></h3><p>No.</p><p>The random image API filters candidates according to the current access mode.</p><h3 id="what-happens-to-old-unrated-images" tabindex="-1">What Happens to Old Unrated Images? <a class="header-anchor" href="#what-happens-to-old-unrated-images" aria-label="Permalink to &quot;What Happens to Old Unrated Images?&quot;">​</a></h3><p>Unrated images are not automatically hidden only because they do not have moderation results. You can adjust their ratings later in the admin panel.</p>',67)])])}const f=t(n,[["render",r]]);export{g as __pageData,f as default};
